def solve(s, k):
    s = s.replace('-', '').upper()
    res = []
    n = len(s)
    first_group = n % k
    if first_group:
        res.append(s[:first_group])
    for i in range(first_group, n, k):
        res.append(s[i:i+k])
    return '-'.join(res)

